document.addEventListener("DOMContentLoaded",(function(){const n=window.location.search,e=new URLSearchParams(n);document.querySelectorAll(".buylink").forEach((n=>{if(n instanceof HTMLAnchorElement){let o=n.href;const t=new URL(o,window.location.origin),c=[];if(e.forEach(((n,e)=>{c.push(`${encodeURIComponent(e)}=${encodeURIComponent(n)}`)})),c.length>0){const e=t.search?"&":"?";n.href=t.href+e+c.join("&")}}}))}));